// Node chamado após Append row in sheet1 (branch Avulso PF/PJ)
// Referencia os dados do Webhook original e do node de Preparar Dados
const wh = $('Webhook').item.json.body;
const prep = $('Preparar Dados p/ Substituição7').item.json;
const cliente = wh.dadosCliente.nome || '';
const area = (wh.dadosNegocio.areas || []).join(', ') || '';
const tipo = wh.tipoFormulario || '';
const advogado = wh.cadastradoPor.nome || '';
const docId = prep.novoDocumentoId || '';
const linkDoc = docId ? `https://docs.google.com/document/d/${docId}/edit` : '(link indisponível)';

const mensagem = [
  '📄 *Novo Contrato para Aprovação!*',
  '',
  `👤 *Cliente:* ${cliente}`,
  `⚖️ *Área:* ${area}`,
  `📋 *Tipo:* ${tipo}`,
  `🧑‍💼 *Gerado por:* ${advogado}`,
  '',
  `🔗 *Contrato:* ${linkDoc}`,
  '',
  'Acesse o sistema para conferir e aprovar o contrato.'
].join('\n');

return [{ json: { mensagem } }];

